const crypto = require('crypto');

const secret = $env.N8N_WEBHOOK_SECRET;
if (!secret) throw new Error('N8N_WEBHOOK_SECRET env var is not set');

const raw = $input.first().json;
const body = raw.body ?? raw;
const headers = raw.headers ?? {};

const receivedSig = (headers['x-akcc-signature'] ?? '').toString();
if (!receivedSig) throw new Error('Missing X-AKCC-Signature header');

const bodyStr = JSON.stringify(body);
const expectedSig = 'sha256=' + crypto
  .createHmac('sha256', secret)
  .update(bodyStr)
  .digest('hex');

const a = Buffer.from(receivedSig);
const b = Buffer.from(expectedSig);
if (a.length !== b.length || !crypto.timingSafeEqual(a, b)) {
  throw new Error('Invalid signature — request rejected');
}

const ts = new Date(body.timestamp);
if (isNaN(ts.getTime()) || Math.abs(Date.now() - ts.getTime()) > 5 * 60 * 1000) {
  throw new Error('Stale timestamp — possible replay attack');
}

if (body.event !== 'giving.received') {
  throw new Error('Unexpected event: ' + body.event);
}

function escHtml(s) {
  return String(s || '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;');
}

const d = body.data;
const amountStr = ((d.amountCents || 0) / 100).toFixed(2);
const fundLabel = { general: 'General Fund', building: 'Building Fund', missions: 'Missions' }[d.fund] || escHtml(d.fund);

return [{
  json: {
    event: body.event,
    donorEmail: d.donorEmail,
    sessionId: d.sessionId,
    amountDisplay: d.currency + ' $' + amountStr,
    fundLabel,
    donorNameHtml: escHtml(d.donorName || 'Anonymous'),
    donorEmailHtml: escHtml(d.donorEmail),
  }
}];
